function isPerfectSquare($num) {
    if (!is_numeric($num) || $num < 0) {
        return "Error: Please enter a non-negative integer.";
    }

    $sqrt = sqrt($num);
    if (floor($sqrt) == $sqrt) {
        return "Yay! Your number is a perfect square!";
    } else {
        return "Sorry, your number is not a perfect square.";
    }
}

